def run_bounded_sql(query: str, rows: list[dict[str, int]]) -> list[dict[str, int]]:
    """
    Execute a tiny SELECT-only SQL fragment over an in-memory table of rows.
    """
    # 1. PRE-VALIDATION AND SETUP
    lower_query = query.lower()
    forbidden_keywords = [
        'insert', 'update', 'delete', 'drop', 'create', 'alter', 'pragma'
    ]
    query_words = lower_query.split()
    if any(keyword in query_words for keyword in forbidden_keywords):
        raise ValueError("Mutating SQL statements are not allowed.")
    if ';' in query:
        raise ValueError("Multi-statement queries are not allowed.")

    all_columns = set(rows[0].keys()) if rows else set()

    # 2. PARSING
    q = query.strip()
    lower_q = q.lower()

    if not lower_q.startswith('select '):
        raise ValueError("Query must start with 'select '.")

    # Find clause boundaries using find() to be robust against spacing issues
    from_pos = lower_q.find(' from ')
    where_pos = lower_q.find(' where ')
    limit_pos = lower_q.find(' limit ')

    if from_pos == -1:
        raise ValueError("Missing 'from' clause.")

    # Validate clause order
    if where_pos != -1 and where_pos < from_pos:
        raise ValueError("'where' clause must appear after 'from'.")
    if limit_pos != -1 and limit_pos < from_pos:
        raise ValueError("'limit' clause must appear after 'from'.")
    if where_pos != -1 and limit_pos != -1 and limit_pos < where_pos:
        raise ValueError("'limit' clause must appear after 'where'.")

    # Determine clause content boundaries
    select_end = from_pos
    from_end = where_pos if where_pos != -1 else (limit_pos if limit_pos != -1 else len(q))
    where_end = limit_pos if limit_pos != -1 else len(q)

    # Parse FROM clause
    from_table_str = q[from_pos + len(' from '):from_end].strip()
    if from_table_str.lower() != 'rows':
        raise ValueError("Can only select from the table named 'rows'.")

    # Parse SELECT clause
    select_cols_str = q[len('select '):select_end].strip()
    is_select_all = False
    if select_cols_str == '*':
        is_select_all = True
        selected_columns = sorted(list(all_columns))
    else:
        selected_columns = [c.strip() for c in select_cols_str.split(',')]
        if not selected_columns or any(not c for c in selected_columns):
            raise ValueError("Invalid column list in select clause.")
        for col in selected_columns:
            if col not in all_columns:
                raise ValueError(f"Unknown column '{col}' in select list.")

    # Parse WHERE clause
    where_clause = None
    if where_pos != -1:
        where_str = q[where_pos + len(' where '):where_end].strip()
        parts = where_str.split()
        if len(parts) != 3:
            raise ValueError("Invalid 'where' clause format. Expected '<column> <op> <integer>'.")

        col, op, val_str = parts
        if col not in all_columns:
            raise ValueError(f"Unknown column '{col}' in 'where' clause.")

        allowed_ops = ['=', '!=', '>', '<', '>=', '<=']
        if op not in allowed_ops:
            raise ValueError(f"Unsupported operator '{op}' in 'where' clause.")

        try:
            val = int(val_str)
        except ValueError:
            raise ValueError(f"'where' clause value must be an integer, but got '{val_str}'.")

        where_clause = (col, op, val)

    # Parse LIMIT clause
    limit_val = None
    if limit_pos != -1:
        limit_str = q[limit_pos + len(' limit '):].strip()
        try:
            limit_val = int(limit_str)
            if limit_val < 0:
                raise ValueError("Limit value cannot be negative.")
        except ValueError:
            raise ValueError(f"Limit value must be an integer, but got '{limit_str}'.")

    # 3. EXECUTION
    if not rows:
        return []

    # Stage 1: Filtering (WHERE)
    if where_clause:
        w_col, w_op, w_val = where_clause
        current_rows = [row for row in rows if w_col in row and _evaluate_where_op(row[w_col], w_op, w_val)]
    else:
        current_rows = list(rows)

    # Stage 2: Limiting (LIMIT)
    if limit_val is not None:
        current_rows = current_rows[:limit_val]

    # Stage 3: Projection (SELECT) - returns copies to prevent mutation
    if is_select_all:
        result = [row.copy() for row in current_rows]
    else:
        result = [{col: row[col] for col in selected_columns} for row in current_rows]

    return result

