import operator as op

class _SafeEvaluator:
    """
    A helper class to safely evaluate a pre-validated AST node.
    It recursively evaluates the tree, performing the allowed operations.
    This class is intended for internal use by `bounded_evaluate`.
    """
    def __init__(self, variables: dict[str, int]):
        self.variables = variables
        # Whitelist of allowed binary operators and their implementations
        self._operators = {
            ast.Add: op.add,
            ast.Sub: op.sub,
            ast.Mult: op.mul,
            ast.FloorDiv: op.floordiv,
        }
        # Whitelist of allowed unary operators and their implementations
        self._unary_operators = {
            ast.USub: op.neg,
        }

    def eval_node(self, node: ast.AST) -> int:
        """Recursively evaluates an AST node."""
        node_type = type(node)

        if isinstance(node, ast.Constant):
            if not isinstance(node.value, int):
                raise TypeError(f"Unsupported constant type: {type(node.value).__name__}")
            return node.value

        if isinstance(node, ast.Name):
            try:
                return self.variables[node.id]
            except KeyError:
                raise NameError(f"Variable '{node.id}' is not defined.")

        if isinstance(node, ast.BinOp):
            op_type = type(node.op)
            if op_type not in self._operators:
                raise TypeError(f"Unsupported binary operator: {op_type.__name__}")
            left = self.eval_node(node.left)
            right = self.eval_node(node.right)
            return self._operators[op_type](left, right)

        if isinstance(node, ast.UnaryOp):
            op_type = type(node.op)
            if op_type not in self._unary_operators:
                raise TypeError(f"Unsupported unary operator: {op_type.__name__}")
            operand = self.eval_node(node.operand)
            return self._unary_operators[op_type](operand)

        if isinstance(node, ast.Expression):
            return self.eval_node(node.body)

        # The pre-validation step should prevent this, but it's a safeguard.
        raise TypeError(f"Unsupported node type: {node_type.__name__}")


def bounded_evaluate(expression: str, variables: dict[str, int], max_nodes: int = 32) -> int:
    """
    Evaluates a simple arithmetic expression string with resource bounds.

    This function safely evaluates an expression by first parsing it into an
    Abstract Syntax Tree (AST), then validating the AST against a strict
    whitelist of allowed nodes and a size limit, and finally computing the
    result.

    Args:
        expression: The arithmetic expression string to evaluate. Supported
                    operations are +, -, *, //, and unary minus.
        variables: A dictionary mapping variable names to integer values.
        max_nodes: The maximum number of nodes allowed in the expression's AST
                   to prevent overly complex expressions.

    Returns:
        The integer result of the evaluation.

    Raises:
        ValueError: If the expression is invalid, uses unsupported features
                    (like function calls, exponentiation, etc.), exceeds the
                    `max_nodes` complexity, contains undefined variables, or
                    results in an error like division by zero.
        TypeError: If `expression` is not a string.
    """
    if not isinstance(expression, str):
        raise TypeError("Expression must be a string.")

    # 1. Parse the expression into an Abstract Syntax Tree (AST).
    try:
        # 'eval' mode is used for parsing a single expression.
        tree = ast.parse(expression, mode='eval')
    except SyntaxError as e:
        raise ValueError(f"Invalid expression syntax: {e}") from e

    # 2. Validate the AST: check node count and types against a whitelist.
    allowed_node_types = {
        ast.Expression, ast.Constant, ast.Name, ast.BinOp, ast.UnaryOp,
        ast.Add, ast.Sub, ast.Mult, ast.FloorDiv, ast.USub,
    }

    node_count = 0
    for node in ast.walk(tree):
        node_count += 1
        if node_count > max_nodes:
            raise ValueError(
                f"Expression exceeds maximum complexity of {max_nodes} nodes."
            )
        if type(node) not in allowed_node_types:
            raise ValueError(f"Unsupported feature in expression: {type(node).__name__}")

    # 3. Evaluate the validated AST using the helper class.
    evaluator = _SafeEvaluator(variables)
    try:
        result = evaluator.eval_node(tree)
        if not isinstance(result, int):
            # This case should not be reachable with the current rules but is a safeguard.
            raise TypeError("Evaluation resulted in a non-integer value.")
        return result
    except (NameError, TypeError) as e:
        # Convert specific evaluation errors into a general ValueError.
        raise ValueError(str(e)) from e
    except ZeroDivisionError:
        # Provide a more user-friendly message for this common error.
        raise ValueError("Division by zero.") from None

